var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이런 미친 자식들!","JPN":"このイカれた連中め！","ENG":"Those crazy bastards!","TWN":"這些瘋子！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"겨우 우릴 잡으려고 동네를 갈아엎을 생각이냐?!","JPN":"俺らを捕まえるために、町全体を壊す気かよ！","ENG":"Do they want to raze the entire neighborhood just to get us?","TWN":"為了抓我們想掀翻整個村子嗎？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지훈! 내가 막는 동안 유리 데리고 뒷문으로 빠져나가!","JPN":"ゴトウ！　俺が足止めするからカスカベを連れて裏門から逃げろ！","ENG":"Jihoon! I'll hold them back while you take Yuri out the back door!","TWN":"智勳！你帶悠麗先離開，我來阻止他們！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐?! 하지만......!","JPN":"え！？　でも……！","ENG":"What?! But—","TWN":"什麼？！可是……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"머뭇거릴 시간 없어! 서둘러!","JPN":"ためらう時間がない！　急げ！","ENG":"There's no time to hesitate! Hurry!","TWN":"沒時間猶豫！快走！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"쿨럭...... 쿨럭......!","JPN":"ゲホッ……ゲホッ……！","ENG":"*Cough, cough*","TWN":"咳咳……咳咳……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"야! 천천히 좀 가!","JPN":"おい、一人で進むなよ、ゆっくり行け！","ENG":"Hey! Slow down!","TWN":"喂！慢一點！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"전부터 느꼈지만 어려서 그런가, 정말 체력 하나는 사람 같지도 않네.","JPN":"前から思ってたけど、若いからか体力だけは人並み外れだな。","ENG":"I don't know if it's because you're young and sprightly, but you're really fit.","TWN":"年輕果然好，妳的體力可不像個普通人類。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"너 혹시 힘을 숨긴 민병대, 뭐 그런 거 아니냐?","JPN":"お前もしかして力を隠した民兵隊、そんな設定だったりするのか？","ENG":"Are you hiding some sort of superpower?","TWN":"妳是不是隱藏力量的民兵隊？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......힘들다면서 농담할 기운은 있나 보네.","JPN":"……しんどいとか言ってるわりに、冗談を言う気力はあるようだな。","ENG":"I guess you've still got enough breath in you to joke around.","TWN":"……你還有餘力說這些嗎。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"힘들 때일수록 여유가 필요한 거야. 너처럼 항상 죽상으로 있는 것보다는 낫지.","JPN":"辛い時こそ、心の余裕が必要なのさ。お前みたいにこの世の終わりみたいな顔をしてるよりマシだ。","ENG":"Hey, a little humor goes a long way, especially when the going gets tough. It sure beats frowning all day like you.","TWN":"人要學會臨危不亂，不能像妳這樣整天哭喪著臉。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그보다 웬 기침이야? 감기라도 걸린 거야?","JPN":"って、その咳はどうした？　風邪でも引いたか？","ENG":"What's with the cough anyway? You got a cold or something?","TWN":"你怎麼咳嗽？感冒了嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......별거 아냐. 요즘 습도가 낮아서 목이 칼칼해서 그래.","JPN":"……大したことない。この頃乾燥してて喉がガラガラなだけだ。","ENG":"... It's nothing. It's just a little dry, that's all.","TWN":"……沒什麼。是因為濕度太低，喉嚨有些乾。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그보다 설마 여기까지 따라오진 않겠지?","JPN":"それより、まさかここまで追いかけては来てないだろうな？","ENG":"Anyway, you don't think they'll follow us all the way here, right?","TWN":"比起這個，他們應該不會追到這裡吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"정말 뒈지는 줄 알았네.","JPN":"今度こそ死ぬかと思った。","ENG":"I thought we were going to kick the bucket for sure this time.","TWN":"還以為真要沒命了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"역시 안 되겠어. 나라도 대장을 도우러 갈래.","JPN":"やっぱりダメだ。私一人だけでも隊長を助けに行く。","ENG":"Alright, that's it. I'm going back there to help the Captain.","TWN":"不行，我要去幫隊長。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 너 미쳤어?","JPN":"は？　お前、正気か？","ENG":"Are you out of your mind?","TWN":"什麼？妳瘋了？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"너 같은 애송이가 가서 뭘 할 수 있는데?","JPN":"お前みたいなガキがそこに戻って何ができるんだ？","ENG":"What's a rookie like you going to do there?","TWN":"妳這種小毛孩去那裡幹什麼？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"괜히 갔다가 발목 잡지 말고 얌전히 숨어 있기나 해.","JPN":"余計な足手まといになるだけだ、大人しく隠れてろ。","ENG":"You'll just slow him down. Just stay put and hide.","TWN":"妳去了也是扯後腿，還是好好躲著吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만...... 그러다가 대장이 당하기라도 하면 어떡해?","JPN":"でも……隊長がやられたらどうする？","ENG":"But... what if they get to him?","TWN":"但是……萬一隊長出事呢？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"뭘 그런 걸 묻고 그래? 당하면 당하는 거지. 지금까지 그래왔으니까.","JPN":"そんなことを聞いてどうするんだ？　やられたら仕方ない。これまでもそうしてきたからな。","ENG":"What of it? It is what it is. That's how it's always been.","TWN":"問這些幹嘛？出事就出事了，不是一直都這樣嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"대장이 선택한 일이야. 그리고 그걸 존중하는 게 우리 민병대의 방식이지.","JPN":"隊長が選んだ道だ。そして、それを尊重するのが俺ら民兵隊の在り方だ。","ENG":"He made his choice, and we must respect that. That's how the Militia works.","TWN":"這是隊長自己做出的選擇，而我們民兵隊要做的就是尊重他的選擇。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"너무 걱정할 거 없어.","JPN":"そんな心配するなって。","ENG":"Don't worry too much though.","TWN":"不用太擔心。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"대장이 그 정도로 쉽게 죽을 위인은 아니니까.","JPN":"隊長は簡単にくたばるような人じゃない。","ENG":"It'll take a lot more to kill the Captain.","TWN":"隊長不會這麼輕易就死。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래...... 알아.","JPN":"ああ……わかっている。","ENG":"Yeah... I know.","TWN":"嗯……我知道。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"하아, 그나저나 정말 골치 아프게 됐네.","JPN":"はあ、しかし厄介なことになったな。","ENG":"Still, I can't help but think we're in some serious trouble now.","TWN":"哎，不過事情變得棘手了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"경찰들 피하는 것만으로도 힘들었는데 범죄조직까지 들쑤셔 놨으니......","JPN":"警察の目を避けるだけでも精一杯だったのに、犯罪組織に狙われる羽目になったし……","ENG":"It was already hard enough running from the cops... Now we've got the gangsters coming after us, too.","TWN":"躲避員警就夠頭痛了，這次又惹上了犯罪集團……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"신참, 넌 지금 이런 생활 지긋지긋하지 않냐?","JPN":"新入り、お前はこんな生活にうんざりしないのか？","ENG":"Don't you ever get sick of this life, rookie?","TWN":"新人，妳不厭倦這樣的生活嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......무슨 말이 하고 싶은 건데?","JPN":"……何が言いたい？","ENG":"What are you trying to say?","TWN":"……什麼意思？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"말 그대로야.","JPN":"言葉どおりだよ。","ENG":"I’m just asking you plainly.","TWN":"就是我問的意思。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"복수를 한답시고 모여서 하는 짓이라곤 인간 백정 노릇뿐이잖아.","JPN":"復讐のために集まって、することはぶっちゃけ殺し屋の仕事で。","ENG":"I mean we're all here to get revenge, but we're nothing but self-glorified serial killers.","TWN":"我們為了復仇聚在一起，過著屠夫的日子。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"다 무너져가는 판잣집에 살면서 먹는 건 개밥보다 못하지.","JPN":"崩れかけのボロコンテナで暮らして、飯は犬の餌以下だろ。","ENG":"We live in shacks and eat no better than stray dogs.","TWN":"在搖搖欲墜的木屋裡生活，吃的東西還不如豬狗。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"엿 같은 카운터 범죄자 놈들을 처단한다고 누가 알아 주는 것도 아니야.","JPN":"悪質なカウンター犯罪者を処刑したって、誰一人認めてくれねえ。","ENG":"It's not like anyone's going to give us a medal for killing those criminal Counters either.","TWN":"也沒有人認可我們處決制裁者犯罪者的功勞。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그 정도면 차라리 다행이지, 괜히 상대를 잘못 건드려서 이젠 마음 놓고 잠도 못 자는 신세가 됐다고.","JPN":"それぐらいならともかく、ドえらい相手を刺激して今じゃ安心して寝ることすらできないんだ。","ENG":"And now it's even worse. We're not going to be able to sleep in peace now that we've stirred the hornet's nest.","TWN":"那還算不錯了。這次又不小心惹毛了大人物，以後的日子更不好過了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"어쩌면 그때...... 대장에게 문신에 대해 얘길 꺼낸 게 실수였을지도 몰라.","JPN":"あの時……隊長にタトゥーについて話したのが間違いだったかもしれない。","ENG":"Maybe... it was a mistake telling the Captain about the tattoo.","TWN":"或許那時……我不應該跟隊長提紋身的事情。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"애초에 이건 대장의 개인적인 복수였을 뿐이잖아?","JPN":"そもそもあれは、隊長の個人的な復讐だろ？","ENG":"This is just his personal vendetta after all, right?","TWN":"這次作戰本來就是隊長的私人復仇而已吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"우리가 이런 리스크를 같이 짊어질 이유가 없었다고.","JPN":"俺らがこんなリスクを一緒に背負う必要なんてないのに。","ENG":"There's no reason why we have to bear the risk with him.","TWN":"我們為什麼要一起冒這個風險。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐야. 갑자기 왜 그래?","JPN":"なんだ、急にどうした？","ENG":"Huh? What's gotten into you?","TWN":"喂，你怎麼說這種話？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 그 녀석을 놓아 주기라도 해야 했다는 거야?","JPN":"それじゃあ、あいつを放してやるべきだったとでも？","ENG":"Are you saying we should have let that scumbag go?","TWN":"那你的意思是我們應該放過那傢伙嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"성냥팔이건 뭐건 애초에 민병대라면 그런 악당들을 심판하는 게 맞잖아!","JPN":"マッチ売りだの何だの、民兵隊はそんな悪党を成敗するのが仕事だろ！","ENG":"We're the Militia. We're supposed to bring villains like that to justice, Matchmaker or not!","TWN":"不管是賣火柴組織還是什麼，我們作為民兵隊必須審判那些壞蛋不是嗎！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 녀석을 잡기 위해서라면...... 난 이 정도 고생쯤은 견딜 만해.","JPN":"あんな奴を捕まえられるなら……私はこの程度の苦労は耐えられる。","ENG":"If we can take down bastards like that... all this other crap is worth it.","TWN":"只要能抓到那傢伙……這點辛苦算不了什麼。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래, 그렇게 생각하고 있다면 다행이네.","JPN":"そうか。そう思ってるならよかった。","ENG":"Okay, then. I'm relieved you think that way.","TWN":"嗯，那就好。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"방금 들은 말은 그냥 한 귀로 흘려 버려.","JPN":"さっきの話は聞き流せばいい。","ENG":"Just ignore what you heard now.","TWN":"不要在意我剛才說的話。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"너무 오래 달리는 바람에 뇌에 산소가 부족해져서 잠깐 헛소리가 나온 것뿐이야.","JPN":"ずっと走りっぱなしで脳に酸素が足りなくて、余計な話をしてしまっただけさ。","ENG":"I must have been babbling because I didn't get enough oxygen to my brain from all that running.","TWN":"可能是因為太累，腦袋有些短路了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......어디로 가는 거야?","JPN":"……どこへ行く？","ENG":"Where are we going?","TWN":"……你要去哪？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"전투가 벌어지기 직전에 무기상을 찾아가자고 했잖아.","JPN":"襲われる前に武器屋に行こうって話しただろ。","ENG":"We were going to visit the gunsmith before the showdown, remember?","TWN":"戰鬥前不是說要去找武器商嗎。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"살아 있으면 대장도 그곳으로 오겠지.","JPN":"生きてるなら隊長もそこに来るだろう。","ENG":"I'm sure the Captain will find his way there, if he's alive.","TWN":"如果隊長還活著，應該也去那裡了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};